def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-((ratio - 0.7) * 15)) + 0.12
        elif 0.4 < ratio <= 0.7:
            score = np.log1p(1 / (ratio+1e-5)) * 0.2 + 0.08
        else:
            for k in range(1, 8):
                sign = -1 if k % 2 == 0 else 1
                score += sign * (ratio ** (k + 2)) / (k * 1.2)
            score = abs(score) + 0.03 if score < 0 else score
        neighbors_influence = 0.0
        max_offset = min(7, n)
        for offset in range(1, max_offset):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset**1.5)
                    factor = np.tanh(diff_ratio * 5)
                    neighbors_influence += factor * weight * 0.1
        capacity_factor = np.sqrt(capacity) + 0.5
        priority = score + neighbors_influence / capacity_factor
        if priority < 0:
            if ratio < 0.3:
                priority = 0.02
            else:
                priority = abs(priority)
        if priority > 1.5:
            priority = 1.5
        if i % 3 == 0:
            volatility = np.sin(i * 2.5) * 0.05
            priority += volatility
            if priority < 0:
                priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            penalties = 0
            for j in range(i-3, i+4):
                if 0 <= j < n and j != i:
                    penalties += (bins[j] if bins[j] > 0 else 0) * 0.01
            priorities[i] = max_finite * (4 + penalties)
    return priorities
